import React, { useState, useEffect, useRef } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';

const API = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

/* ── Fingerprint component ── */
function FingerprintGate({ onVerified }) {
  const [status, setStatus] = useState('idle'); // idle | scanning | done | skipped
  const canvasRef = useRef();
  const animRef = useRef();

  const startScan = async () => {
    setStatus('scanning');
    // Animate fingerprint pulse
    let frame = 0;
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = canvas.getContext('2d');
      const draw = () => {
        frame++;
        ctx.clearRect(0, 0, 120, 120);
        const r = 40 + Math.sin(frame * 0.08) * 6;
        const alpha = 0.3 + Math.sin(frame * 0.1) * 0.2;
        ctx.beginPath();
        ctx.arc(60, 60, r + 20, 0, Math.PI * 2);
        ctx.strokeStyle = `rgba(239,68,68,${alpha * 0.4})`;
        ctx.lineWidth = 2;
        ctx.stroke();
        ctx.beginPath();
        ctx.arc(60, 60, r, 0, Math.PI * 2);
        ctx.strokeStyle = `rgba(239,68,68,${alpha})`;
        ctx.lineWidth = 3;
        ctx.stroke();
        // Scan line
        const scanY = 20 + ((frame * 1.5) % 80);
        ctx.fillStyle = `rgba(239,68,68,0.5)`;
        ctx.fillRect(20, scanY, 80, 2);
        // Fingerprint lines
        for (let i = 0; i < 8; i++) {
          const y = 30 + i * 9;
          const w = 30 + Math.sin(i * 0.8) * 20;
          ctx.beginPath();
          ctx.arc(60, 60, 8 + i * 5, Math.PI * 0.2, Math.PI * 0.8);
          ctx.strokeStyle = `rgba(239,68,68,${0.2 + i * 0.06})`;
          ctx.lineWidth = 1.5;
          ctx.stroke();
        }
        animRef.current = requestAnimationFrame(draw);
      };
      draw();
    }

    // Try WebAuthn / device biometrics
    let fingerprintHash = null;
    try {
      if (window.PublicKeyCredential) {
        const challenge = new Uint8Array(32);
        crypto.getRandomValues(challenge);
        const credential = await navigator.credentials.get({
          publicKey: {
            challenge,
            timeout: 10000,
            userVerification: 'preferred',
            rpId: window.location.hostname
          }
        });
        fingerprintHash = btoa(String.fromCharCode(...new Uint8Array(credential.response.authenticatorData))).substring(0, 32);
      }
    } catch (e) {
      // Biometrics not available or skipped — that's fine, we still log IP
      fingerprintHash = 'device-' + navigator.userAgent.substring(0, 20).replace(/\s/g, '');
    }

    cancelAnimationFrame(animRef.current);
    setTimeout(() => {
      setStatus('done');
      onVerified(fingerprintHash);
    }, 800);
  };

  useEffect(() => () => cancelAnimationFrame(animRef.current), []);

  if (status === 'done') return null;

  return (
    <div style={{
      position: 'fixed', inset: 0, zIndex: 999,
      background: 'rgba(10,15,30,0.97)',
      display: 'flex', flexDirection: 'column',
      alignItems: 'center', justifyContent: 'center',
      padding: 24, backdropFilter: 'blur(8px)'
    }}>
      {/* Top bar */}
      <div style={{
        position: 'absolute', top: 0, left: 0, right: 0,
        height: 4,
        background: 'linear-gradient(90deg, #ef4444, #f59e0b, #ef4444)',
        backgroundSize: '200% 100%',
        animation: 'shimmer 2s linear infinite'
      }} />
      <style>{`@keyframes shimmer { to { background-position: -200% 0; } }`}</style>

      <div style={{
        background: 'rgba(239,68,68,0.1)', border: '1px solid rgba(239,68,68,0.3)',
        borderRadius: 999, padding: '6px 16px', marginBottom: 32,
        fontSize: 12, fontWeight: 700, color: '#fca5a5', letterSpacing: '0.1em'
      }}>
        🚨 EMERGENCY MEDICAL ACCESS
      </div>

      <div style={{ fontSize: 52, marginBottom: 8 }}>❤️‍🔥</div>
      <h1 style={{
        fontFamily: 'Space Grotesk', fontSize: 28, fontWeight: 700,
        color: '#f1f5f9', marginBottom: 8, textAlign: 'center'
      }}>LifeQR</h1>
      <p style={{ color: '#94a3b8', textAlign: 'center', marginBottom: 40, maxWidth: 320, lineHeight: 1.7 }}>
        You are about to access someone's emergency medical information. For accountability, your device identity will be logged.
      </p>

      {/* Fingerprint animation canvas */}
      <div style={{
        width: 120, height: 120, marginBottom: 32, position: 'relative',
        display: 'flex', alignItems: 'center', justifyContent: 'center'
      }}>
        {status === 'idle' && (
          <div style={{ fontSize: 72, filter: 'drop-shadow(0 0 20px rgba(239,68,68,0.4))' }}>👆</div>
        )}
        {status === 'scanning' && (
          <canvas ref={canvasRef} width={120} height={120} />
        )}
      </div>

      {status === 'idle' && (
        <button onClick={startScan} style={{
          background: 'var(--red, #ef4444)', color: 'white', border: 'none',
          borderRadius: 16, padding: '18px 40px',
          fontFamily: 'Space Grotesk', fontSize: 17, fontWeight: 700,
          cursor: 'pointer', marginBottom: 16,
          boxShadow: '0 0 30px rgba(239,68,68,0.4)'
        }}>
          👆 Verify & View Emergency Info
        </button>
      )}

      {status === 'scanning' && (
        <div style={{ color: '#94a3b8', fontSize: 15, display: 'flex', alignItems: 'center', gap: 8 }}>
          <div style={{
            width: 18, height: 18, border: '2px solid rgba(239,68,68,0.4)',
            borderTop: '2px solid #ef4444', borderRadius: '50%',
            animation: 'spin 0.7s linear infinite'
          }} />
          <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
          Verifying identity...
        </div>
      )}

      <button onClick={() => { onVerified(null); setStatus('done'); }}
        style={{
          background: 'none', border: 'none', color: '#64748b',
          fontSize: 13, cursor: 'pointer', marginTop: 16, textDecoration: 'underline'
        }}>
        Skip verification (view anyway)
      </button>

      <p style={{ fontSize: 11, color: '#475569', marginTop: 24, textAlign: 'center', maxWidth: 300, lineHeight: 1.6 }}>
        This access is logged for the safety of the QR card owner. Misuse is prohibited.
      </p>
    </div>
  );
}

/* ── Main Scan Page ── */
export default function ScanPage() {
  const { token } = useParams();
  const [data, setData] = useState(null);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [verified, setVerified] = useState(false);
  const [callingId, setCallingId] = useState(null);

  const handleVerified = async (fingerprintHash) => {
    setVerified(true);
    setLoading(true);
    try {
      // Get location
      let lat = null, lng = null;
      try {
        await new Promise(resolve => {
          navigator.geolocation.getCurrentPosition(
            pos => { lat = pos.coords.latitude; lng = pos.coords.longitude; resolve(); },
            () => resolve(), { timeout: 4000 }
          );
        });
      } catch {}

      const params = new URLSearchParams();
      if (fingerprintHash) params.append('fingerprint_hash', fingerprintHash);
      if (lat) params.append('location_lat', lat);
      if (lng) params.append('location_lng', lng);

      const res = await axios.get(`${API}/public/scan/${token}?${params}`);
      setData(res.data);
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to load emergency information.');
    } finally {
      setLoading(false);
    }
  };

  const callContact = (contact) => {
    setCallingId(contact.id);
    window.location.href = `tel:${contact.phone}`;
    setTimeout(() => setCallingId(null), 3000);
  };

  const openMaps = () => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(pos => {
        const { latitude, longitude } = pos.coords;
        window.open(`https://maps.google.com/?q=${latitude},${longitude}`, '_blank');
      });
    }
  };

  return (
    <>
      {!verified && <FingerprintGate onVerified={handleVerified} />}

      <div style={{
        minHeight: '100vh',
        background: 'linear-gradient(180deg, #0a0f1e 0%, #111827 100%)',
        padding: '0 0 60px',
        fontFamily: "'DM Sans', sans-serif"
      }}>
        {/* Emergency header strip */}
        <div style={{
          background: '#ef4444',
          padding: '10px 20px',
          display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 10
        }}>
          <span style={{ fontSize: 16 }}>🚨</span>
          <span style={{ fontFamily: 'Space Grotesk', fontWeight: 700, color: 'white', fontSize: 14, letterSpacing: '0.06em' }}>
            EMERGENCY MEDICAL INFORMATION
          </span>
          <span style={{ fontSize: 16 }}>🚨</span>
        </div>

        {/* Logo */}
        <div style={{ textAlign: 'center', padding: '24px 20px 0' }}>
          <div style={{ fontSize: 32, marginBottom: 4 }}>❤️‍🔥</div>
          <div style={{ fontFamily: 'Space Grotesk', fontWeight: 700, fontSize: 20, color: '#ef4444' }}>
            Life<span style={{ color: '#f1f5f9' }}>QR</span>
          </div>
        </div>

        {loading && (
          <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '40vh' }}>
            <div style={{
              width: 48, height: 48, border: '3px solid rgba(239,68,68,0.2)',
              borderTop: '3px solid #ef4444', borderRadius: '50%',
              animation: 'spin 0.7s linear infinite'
            }} />
            <style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style>
          </div>
        )}

        {error && (
          <div style={{ maxWidth: 420, margin: '40px auto', padding: '0 20px', textAlign: 'center' }}>
            <div style={{ fontSize: 48, marginBottom: 16 }}>❌</div>
            <h2 style={{ fontFamily: 'Space Grotesk', color: '#f1f5f9', marginBottom: 8 }}>QR Code Invalid</h2>
            <p style={{ color: '#94a3b8' }}>{error}</p>
          </div>
        )}

        {data && (
          <div style={{ maxWidth: 480, margin: '0 auto', padding: '24px 16px' }}>

            {/* Person Card */}
            <div style={{
              background: 'linear-gradient(135deg, #1a1a2e, #16213e)',
              border: '1px solid rgba(239,68,68,0.4)',
              borderRadius: 20, padding: 24, marginBottom: 20,
              boxShadow: '0 0 40px rgba(239,68,68,0.15)'
            }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 16, marginBottom: 20 }}>
                <div style={{
                  width: 64, height: 64, borderRadius: '50%',
                  background: 'rgba(239,68,68,0.2)',
                  border: '2px solid rgba(239,68,68,0.5)',
                  display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 28
                }}>👤</div>
                <div>
                  <h2 style={{ fontFamily: 'Space Grotesk', fontSize: 22, fontWeight: 700, color: '#f1f5f9', marginBottom: 4 }}>
                    {data.profile.full_name}
                  </h2>
                  {data.profile.date_of_birth && (
                    <div style={{ fontSize: 13, color: '#94a3b8' }}>
                      DOB: {new Date(data.profile.date_of_birth).toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' })}
                    </div>
                  )}
                  {data.profile.gender && (
                    <div style={{ fontSize: 13, color: '#94a3b8' }}>{data.profile.gender}</div>
                  )}
                </div>
              </div>

              {/* Vital badges */}
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: 10, marginBottom: 4 }}>
                {data.profile.blood_type && (
                  <div style={{
                    background: '#ef4444', color: 'white', borderRadius: 8,
                    padding: '6px 14px', fontFamily: 'Space Grotesk',
                    fontWeight: 700, fontSize: 15, display: 'flex', alignItems: 'center', gap: 6
                  }}>
                    🩸 {data.profile.blood_type}
                  </div>
                )}
                {data.profile.organ_donor ? (
                  <div style={{
                    background: 'rgba(16,185,129,0.2)', border: '1px solid rgba(16,185,129,0.4)',
                    color: '#6ee7b7', borderRadius: 8, padding: '6px 14px', fontSize: 13, fontWeight: 600
                  }}>
                    🫀 Organ Donor
                  </div>
                ) : null}
              </div>
            </div>

            {/* Medical Info */}
            {(data.profile.allergies || data.profile.medical_conditions || data.profile.current_medications) && (
              <div style={{
                background: '#1f2937', border: '1px solid #374151',
                borderRadius: 16, padding: 20, marginBottom: 20
              }}>
                <h3 style={{ fontFamily: 'Space Grotesk', fontWeight: 600, fontSize: 15, color: '#f1f5f9', marginBottom: 16 }}>
                  🏥 Medical Information
                </h3>

                {data.profile.allergies && (
                  <div style={{ marginBottom: 14 }}>
                    <div style={{
                      display: 'inline-flex', alignItems: 'center', gap: 6,
                      background: 'rgba(239,68,68,0.1)', border: '1px solid rgba(239,68,68,0.3)',
                      borderRadius: 6, padding: '3px 10px', fontSize: 11, fontWeight: 700,
                      color: '#fca5a5', marginBottom: 6, letterSpacing: '0.06em'
                    }}>
                      ⚠️ ALLERGIES
                    </div>
                    <div style={{ fontSize: 14, color: '#f1f5f9', lineHeight: 1.6 }}>{data.profile.allergies}</div>
                  </div>
                )}

                {data.profile.medical_conditions && (
                  <div style={{ marginBottom: 14 }}>
                    <div style={{
                      display: 'inline-flex', alignItems: 'center', gap: 6,
                      background: 'rgba(245,158,11,0.1)', border: '1px solid rgba(245,158,11,0.3)',
                      borderRadius: 6, padding: '3px 10px', fontSize: 11, fontWeight: 700,
                      color: '#fcd34d', marginBottom: 6, letterSpacing: '0.06em'
                    }}>
                      🩺 CONDITIONS
                    </div>
                    <div style={{ fontSize: 14, color: '#f1f5f9', lineHeight: 1.6 }}>{data.profile.medical_conditions}</div>
                  </div>
                )}

                {data.profile.current_medications && (
                  <div>
                    <div style={{
                      display: 'inline-flex', alignItems: 'center', gap: 6,
                      background: 'rgba(59,130,246,0.1)', border: '1px solid rgba(59,130,246,0.3)',
                      borderRadius: 6, padding: '3px 10px', fontSize: 11, fontWeight: 700,
                      color: '#93c5fd', marginBottom: 6, letterSpacing: '0.06em'
                    }}>
                      💊 MEDICATIONS
                    </div>
                    <div style={{ fontSize: 14, color: '#f1f5f9', lineHeight: 1.6 }}>{data.profile.current_medications}</div>
                  </div>
                )}

                {data.profile.doctor_name && (
                  <div style={{
                    marginTop: 14, paddingTop: 14,
                    borderTop: '1px solid #374151', fontSize: 13, color: '#94a3b8'
                  }}>
                    👨‍⚕️ Doctor: <strong style={{ color: '#f1f5f9' }}>{data.profile.doctor_name}</strong>
                    {data.profile.doctor_phone && (
                      <a href={`tel:${data.profile.doctor_phone}`} style={{
                        display: 'block', marginTop: 4, color: '#3b82f6', textDecoration: 'none', fontSize: 14
                      }}>
                        📞 {data.profile.doctor_phone}
                      </a>
                    )}
                  </div>
                )}
              </div>
            )}

            {/* Emergency Contacts — THE KEY SECTION */}
            {data.contacts && data.contacts.length > 0 && (
              <div style={{ marginBottom: 20 }}>
                <h3 style={{
                  fontFamily: 'Space Grotesk', fontWeight: 700, fontSize: 16,
                  color: '#f1f5f9', marginBottom: 14, display: 'flex', alignItems: 'center', gap: 8
                }}>
                  <span style={{
                    background: '#ef4444', borderRadius: 8, width: 28, height: 28,
                    display: 'inline-flex', alignItems: 'center', justifyContent: 'center', fontSize: 14
                  }}>📞</span>
                  Emergency Contacts
                </h3>

                <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
                  {data.contacts.map((contact, i) => (
                    <div key={contact.id} style={{
                      background: i === 0
                        ? 'linear-gradient(135deg, rgba(239,68,68,0.12), rgba(239,68,68,0.06))'
                        : '#1f2937',
                      border: i === 0 ? '1px solid rgba(239,68,68,0.4)' : '1px solid #374151',
                      borderRadius: 16, padding: '16px 18px',
                      boxShadow: i === 0 ? '0 0 20px rgba(239,68,68,0.1)' : 'none'
                    }}>
                      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 12 }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                          <div style={{
                            width: 44, height: 44, borderRadius: '50%',
                            background: i === 0 ? 'rgba(239,68,68,0.2)' : '#374151',
                            border: `1px solid ${i === 0 ? 'rgba(239,68,68,0.4)' : '#4b5563'}`,
                            display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 20
                          }}>
                            {i === 0 ? '⭐' : '👤'}
                          </div>
                          <div>
                            <div style={{ fontFamily: 'Space Grotesk', fontWeight: 600, fontSize: 16, color: '#f1f5f9' }}>
                              {contact.name}
                            </div>
                            <div style={{ fontSize: 13, color: '#94a3b8' }}>{contact.relationship}</div>
                          </div>
                        </div>
                        {i === 0 && (
                          <span style={{
                            background: '#ef4444', color: 'white', borderRadius: 6,
                            padding: '3px 10px', fontSize: 11, fontWeight: 700
                          }}>PRIMARY</span>
                        )}
                      </div>

                      {/* CALL NOW button — number hidden */}
                      <button
                        onClick={() => callContact(contact)}
                        style={{
                          width: '100%',
                          background: callingId === contact.id
                            ? 'rgba(16,185,129,0.8)'
                            : i === 0 ? '#ef4444' : '#374151',
                          color: 'white', border: 'none',
                          borderRadius: 12, padding: '14px 20px',
                          fontFamily: 'Space Grotesk', fontSize: 16, fontWeight: 700,
                          cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 10,
                          transition: 'all 0.2s',
                          boxShadow: i === 0 ? '0 4px 20px rgba(239,68,68,0.4)' : 'none'
                        }}
                      >
                        {callingId === contact.id ? (
                          <><span style={{ fontSize: 20 }}>📲</span> Calling...</>
                        ) : (
                          <><span style={{ fontSize: 20 }}>📞</span> Call Now</>
                        )}
                      </button>
                      <p style={{ textAlign: 'center', fontSize: 11, color: '#64748b', marginTop: 8 }}>
                        Number hidden for privacy · tap to call
                      </p>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Share Location */}
            <button onClick={openMaps} style={{
              width: '100%', background: '#1f2937',
              border: '1px solid #374151', color: '#f1f5f9',
              borderRadius: 12, padding: '14px 20px',
              fontFamily: 'Space Grotesk', fontSize: 14, fontWeight: 600,
              cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 10,
              marginBottom: 12
            }}>
              📍 View Accident Location on Maps
            </button>

            {/* Scanned at */}
            <div style={{ textAlign: 'center', fontSize: 11, color: '#475569', marginTop: 16 }}>
              Scanned: {new Date(data.scannedAt).toLocaleString()}<br />
              LifeQR — Emergency Medical Identity
            </div>
          </div>
        )}
      </div>
    </>
  );
}
